const tasks = $('Get All Tasks').first().json;
const status = $('Get Status').first().json;

const allTasks = tasks.tasks || [];
const now = new Date();
const weekAgo = new Date(now - 7 * 24 * 60 * 60 * 1000);

const thisWeek = allTasks.filter(t => new Date(t.created_at) >= weekAgo);
const done = thisWeek.filter(t => t.state === 'done');
const failed = thisWeek.filter(t => t.state === 'failed');
const open = allTasks.filter(t => !['done','failed'].includes(t.state));

const platform = status.platform || {};
const online = Number(platform.online_count || 0);
const registered = Number(platform.registered_count || online);

const byAgent = {};
for (const t of done) {
  const a = t.assigned_to || 'unassigned';
  byAgent[a] = (byAgent[a] || 0) + 1;
}

const agentLines = Object.entries(byAgent)
  .sort((a,b) => b[1] - a[1])
  .map(([a,c]) => `  ${a}: ${c} Tasks`)
  .join('\n');

const report = [
  'WOCHENREPORT',
  `${weekAgo.toISOString().split('T')[0]} bis ${now.toISOString().split('T')[0]}`,
  `Agents: ${online}/${registered} online`,
  `Tasks: ${done.length} erledigt, ${failed.length} fehlgeschlagen, ${open.length} offen`,
  agentLines ? `Performance:\n${agentLines}` : 'Keine erledigten Tasks',
].join('\n');

return [{ json: { body: report } }];
